const Keys={ESCAPE:"Escape",ESC:"Esc"},isEscEvent=e=>e.key===Keys.ESCAPE||e.key===Keys.ESC,popup=document.querySelector(".popup");if(popup){const e=popup.querySelector(".popup__close"),t=()=>{popup.classList.add("popup--open"),document.body.classList.add("no-scroll"),document.addEventListener("keydown",o)},l=()=>{popup.classList.remove("popup--open"),document.body.classList.remove("no-scroll"),document.removeEventListener("keydown",o)},o=e=>{isEscEvent(e)&&(e.preventDefault(),l())};e.addEventListener("click",l),t()}const numberField=document.querySelector(".number-field");if(numberField){const e=numberField.querySelector(".number-field__control");numberField.querySelector(".number-field__button--minus").addEventListener("click",(()=>{e.stepDown()})),numberField.querySelector(".number-field__button--plus").addEventListener("click",(()=>{e.stepUp()}))}const thumbnailSlider=document.querySelector(".thumbnail-slider");if(thumbnailSlider){const e=new Swiper(".thumbnail-slider__thumbs",{direction:"vertical",spaceBetween:5,loop:!0,slidesPerView:2.5,freeMode:!0,watchSlidesProgress:!0,breakpoints:{1020:{spaceBetween:10,slidesPerView:2.45}}});new Swiper(".thumbnail-slider__full",{loop:!0,thumbs:{swiper:e}})}const likeButton=document.querySelector(".social-button--like");likeButton&&likeButton.addEventListener("click",(()=>{likeButton.classList.toggle("social-button--like-active")}));const clipbox=document.querySelector(".clipbox");clipbox&&clipbox.querySelector(".clipbox__toggler").addEventListener("click",(()=>{clipbox.classList.toggle("clipbox--reduced"),clipbox.classList.toggle("clipbox--expanded")}));const worksGallerySlider=document.querySelector(".works-gallery__slider");if(worksGallerySlider){new Swiper(".works-gallery__slider",{slidesPerView:"auto",spaceBetween:5,freeMode:!0,navigation:{nextEl:".works-gallery__slider .swiper-button-next",prevEl:".works-gallery__slider .swiper-button-prev"},breakpoints:{1020:{spaceBetween:18}}})}